const articles = $input.all().map(i => i.json).filter(a => a.id);

if (articles.length === 0) {
  return [{ json: { done: true, processed: 0, remaining: 0 } }];
}

const articleList = articles.map((a, i) =>
  `Article ${i} (id=${a.id}, topic=${a.topic}): ${a.title}\n${a.content_snippet || 'No content available'}`
).join('\n\n---\n\n');

const systemPrompt = `You analyze news articles for a specific user. For each article, return a JSON object with key "articles" containing an array. Each element must have:
- "id": the article id (number)
- "summary": a 2-3 sentence summary explaining what the article is about and why it matters TO THIS USER
- "relevance_score": 1-10 rating of how interesting this article is TO THIS USER specifically. BE STRICT — most articles 4-7. Only 8-10 for direct matches with the user's interests below.
- "tags": array of up to 5 keyword tags

USER PROFILE (drives 'ai' topic scoring):
The user is a homelab tinkerer and AI-assisted developer. Their main AI interests are PRACTICAL Claude Code / Cursor / Copilot usage — actually shipping things with these tools. Specifically:
- Claude Code workflow tips (skills, sub-agents, parallel agents, worktrees, planning, code review patterns, MCP servers, custom commands)
- AI coding tools comparison (Claude Code vs Cursor vs Copilot vs ChatGPT, when to pick which)
- Productivity & ethics with AI coding (productivity gains, "is it cheating", what changes about being a developer)
- Shipping AI-built apps (packaging, code signing, distribution, monetization, deployment)
- Agentic patterns (orchestration, sub-agents, planning phases, context management, memory systems)
- LLM news that affects practical use (model releases that change what's possible for coding, context window changes, pricing)
- Self-hosted AI / local LLMs that are actually usable for coding
NOT interested in: AI policy/regulation, AI art, theoretical research papers, AI in non-coding business contexts, generic AI hype.

STRICT scoring per topic:
- "ai": 9-10 ONLY for articles directly hitting the user-profile bullets above. 7-8 for general LLM news that affects practical coding (model releases, tool updates). 5-6 for tangentially relevant AI dev news. 3-4 for AI policy/art/hype. The user's homelab + coding lens is the filter — a Claude Code workflow tip outranks a foundation-model paper.
- "music": 9-10 for music creation tools, DAW tips, AI music generation, synthesizers. 5-7 for general music discussion.
- "computers": 9-10 for homelab builds, self-hosting guides, networking, Synology/NAS, Pi-hole, Home Assistant. 5-7 for general hardware/IT.
- "tech": 9-10 for significant tech news. 5-7 for minor updates.

Return ONLY valid JSON.`;

const requestBody = JSON.stringify({
  model: 'gpt-4o-mini',
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: articleList }
  ],
  temperature: 0.3,
  max_tokens: 2000
});

return [{ json: { requestBody, articleIds: articles.map(a => a.id), count: articles.length } }];

const aiResponse = $json;
const content = aiResponse?.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  return [{ json: { error: 'Failed to parse OpenAI response', raw: content.substring(0, 200) } }];
}

const articles = parsed.articles || [];
const updates = [];

for (const a of articles) {
  if (!a.id) continue;
  const esc = (v) => v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  const tags = JSON.stringify(a.tags || []);
  const score = Math.min(10, Math.max(1, parseInt(a.relevance_score) || 5));
  updates.push(`UPDATE news_articles SET ai_summary = ${esc(a.summary)}, ai_tags = '${tags.replace(/'/g, "\\'")}', relevance_score = ${score} WHERE id = ${a.id}`);
}

if (updates.length === 0) {
  return [{ json: { processed: 0, sql: 'SELECT 1' } }];
}

return [{ json: { processed: updates.length, sql: updates.join(';\n') } }];
